};
```

**L760**을 통한 간접 호출도 존재:
```typescript
const blockOnlyIfAtHardContextLimit = async (userContent: string): Promise<void> => {
  await blockAtHardContextLimit(estimateTokens(userContent), "new-turn");
};
```

---

### 2. Blocking 조건 상세 분석

#### 2.1 `blockAtHardLimit` 메서드 (compaction-orchestrator.ts L550-604)

```typescript
async blockAtHardLimit(
  historyOrAdditionalTokens: CompactionHistoryLike | number,
  additionalTokensOrPhase: number | CompactionPhase,
  maybePhase?: CompactionPhase
): Promise<boolean> {
  // 1. History 객체 확인
  const history = this.resolveHistory(...);
  if (!history) return false;

  // 2. Hard limit 체크
  const blocking = this.isAtHardLimit(history, additionalTokens, phase);
  if (!blocking) return false;  // ← hard limit이 아니면 즉시 반환

  // 3. Blocking 시작
  this.callbacks.onBlockingChange?.(true);
  try {
    // 4. Prune 시도
    const pruneHandled = await this.tryPruneBeforeOverflow(...);

    // 5. Prune 실패 시 overflow 처리
    if (!pruneHandled) {
      await this.handleOverflow(new Error("context_limit_hard_block"));
    }
  } finally {
    this.callbacks.onBlockingChange?.(false);
  }

  // 6. 여전히 초과 상태인지 확인
  if (this.isAtHardLimit(history, additionalTokens, phase)) {
    this.callbacks.onStillExceeded?.();
  }

  return true;
}
```

#### 2.2 Hard Limit 판별 로직 (`isAtHardLimit` L694-721)

```typescript
private isAtHardLimit(
  history: CompactionHistoryLike,
  additionalTokens: number,
  phase: CompactionPhase
): boolean {
  // 1. History의 직접 메서드 사용 (있는 경우)
  if (typeof history.isAtHardContextLimit === "function") {
    return history.isAtHardContextLimit(additionalTokens, { phase });
  }

  // 2. 폴백: 직접 계산
  const config = history.getCompactionConfig();
  const contextLimit = config.contextLimit ?? 0;
  if (contextLimit <= 0) return false;

  // 3. Phase별 reserve token 배율 적용
  const phaseMultiplier = phase === "intermediate-step" ? 2 : 1;
  const reserveTokens = Math.max(0, (config.reserveTokens ?? 0) * phaseMultiplier);

  // 4. Hard limit 체크 함수 호출
  return isAtHardContextLimitFromUsage({
    contextLimit,
    currentUsageTokens: history.getEstimatedTokens(),
    enabled: config.enabled ?? false,
    reserveTokens,
    additionalTokens,
  });
}
```

#### 2.3 최종 조건식 (`isAtHardContextLimitFromUsage` compaction-policy.ts L68-88)

```typescript
export function isAtHardContextLimitFromUsage(params: {
  additionalTokens?: number;
  contextLimit: number;
  currentUsageTokens: number;
  enabled: boolean;
  reserveTokens: number;
}): boolean {
  const { additionalTokens = 0, contextLimit, currentUsageTokens, enabled, reserveTokens } = params;

  // 조건 1: Compaction이 활성화되어 있어야 함
  if (!enabled) return false;

  // 조건 2: Hard limit 초과 체크
  return currentUsageTokens + additionalTokens + reserveTokens >= contextLimit;
}
```

**📌 Blocking 발생 조건 정리:**
1. `enabled === true` (compaction 활성화)
2. `currentUsageTokens + additionalTokens + reserveTokens >= contextLimit`

여기서 `reserveTokens`는 phase에 따라 다름:
- `"new-turn"`: `config.reserveTokens`
- `"intermediate-step"`: `config.reserveTokens * 2` (더 보수적)

---

### 3. Compaction 실패 시 복구 전략

#### 3.1 `handleOverflow` 흐름 (checkpoint-history.ts L695-798)

