#### 3.2 각 전략 상세

**Strategy 1: Prune (`tryPruneRecovery` L1174-1223)**
```typescript
private tryPruneRecovery(tokensBefore, contextLimit): OverflowRecoveryResult | null {
  if (!this.pruningConfig.enabled) return null;

  const pruneResult = pruneToolOutputs(activeMessages, this.pruningConfig);
  if (pruneResult.prunedCount === 0) return null;

  // 메시지 적용 후 토큰 감소 확인
  const tokensAfter = this.getEstimatedTokens();
  if (!this.evaluateRecoveryAttempt({ contextLimit, tokensAfter, tokensBefore })) {
    return null;  // 충분히 줄지 못함 → 다음 전략으로
  }

  return { success: true, strategy: "prune", tokensBefore, tokensAfter };
}
```

**Strategy 2 & 3: Compact (`compactForOverflowRecovery` L1242-1368)**
```typescript
private async compactForOverflowRecovery(aggressive: boolean, ...): Promise<OverflowRecoveryResult | null> {
  // 1. 사전 조건 체크
  if (!(this.compactionConfig.enabled && this.compactionConfig.summarizeFn)) {
    return null;
  }

  // 2. 스냅샷 저장 (롤백용)
  const snapshot = { messages: [...this.messages], summaryMessageId, revision };

  // 3. Compaction 대상 결정
  if (aggressive) {
    messagesToSummarize = activeMessages;  // 전체
    messagesToKeep = [];
  } else {
    // 일반: split index 기준으로 분할
    messagesToSummarize = activeMessages.slice(0, splitIndex);
    messagesToKeep = activeMessages.slice(splitIndex);
  }

  // 4. 요약 생성
  try {
    summaryText = await this.compactionConfig.summarizeFn(...);
  } catch {
    // 롤백
    this.messages = snapshot.messages;
    this.summaryMessageId = snapshot.summaryMessageId;
    return null;
  }

  // 5. 결과 평가
  if (!this.evaluateRecoveryAttempt({ contextLimit, tokensAfter, tokensBefore })) {
    // 롤백
    this.messages = snapshot.messages;
    return null;
  }

  return { success: true, strategy: aggressive ? "aggressive-compact" : "compact", ... };
}
```

**Strategy 4: Truncate (`tryTruncateRecovery` L1370-1443)**
```typescript
private tryTruncateRecovery(tokensBefore, contextLimit): OverflowRecoveryResult | null {
  if (contextLimit <= 0) return null;

  // Phase 1: Non-summary 메시지부터 제거
  while (this.getEstimatedTokens() >= contextLimit && this.messages.length > 1) {
    const oldestNonSummaryIdx = this.messages.findIndex(m => !m.isSummary);
    if (oldestNonSummaryIdx === -1) break;
    this.messages.splice(oldestNonSummaryIdx, 1);
    this.revision += 1;
  }

  // Phase 2: 모든 메시지 제거 (summary 포함)
  while (this.getEstimatedTokens() >= contextLimit && this.messages.length > 1) {
    this.messages.splice(0, 1);
    this.revision += 1;
  }

  // Phase 3: 최후 수단 - 마지막 user message만 남김
  if (this.getEstimatedTokens() >= contextLimit) {
    const lastUserMessage = [...this.messages].reverse().find(m => m.message.role === "user");
    const fallbackMessage = lastUserMessage ?? this.messages.at(-1);
    this.messages = [fallbackMessage];
    this.summaryMessageId = null;
    this.revision += 1;
  }

  // 여전히 초과면 실패
  if (tokensAfter >= contextLimit) {
    return {
      success: false,
      error: "context window too small for remaining content"
    };
  }

  return { success: true, strategy: "truncate", ... };
}
```

#### 3.3 `handleOverflow` 메서드 (compaction-orchestrator.ts L380-412)

```typescript
async handleOverflow(error?: unknown): Promise<OverflowRecoveryResult> {
  const history = this.requireHistory();

  // CheckpointHistory에 handleContextOverflow이 있으면 위임
  if (!history.handleContextOverflow) {
    // 폴백: 직접 aggressive compaction 시도
    const fallback = await this.runCompaction(history, { auto: true, aggressive: true });
    return {
      success: fallback.success,
      tokensBefore: fallback.tokensBefore,
      tokensAfter: fallback.tokensAfter,
      error: fallback.success ? undefined : fallback.reason,
      strategy: fallback.success ? "aggressive-compact" : undefined,
    };
  }

  // 위임
  this.callbacks.onCompactionStart?.();
  try {
    return await history.handleContextOverflow(error);
  } catch (overflowError) {
    this.reportError("Overflow recovery failed", overflowError);
    return {
      success: false,
      tokensBefore: history.getEstimatedTokens(),
      tokensAfter: history.getEstimatedTokens(),
      error: overflowError instanceof Error ? overflowError.message : String(overflowError),
    };
  }
}
```

